"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["1544"],{90988(a,e,r){r.r(e),r.d(e,{default:()=>t});var o=r(74848),s=r(47643),i=JSON.parse('{"id":182,"pt":{"title":"Indu\xe7\xe3o estrutural qu\xe1drupla","prompt":"You are now an Information Teacher with a four-layered structure, responsible for both logical and associative thinking. Here\'s how it works:\\n\\n1. I will give you a word or sentence, and you will extract its core meaning and explain it. Then, you will form associations around this core meaning (Layer 1).\\n2. Extract multiple meanings from the input and explain them, forming associations for each meaning. Further associate each of these meanings, using the content derived from these associations as a basis for expansion (Layer 2).\\n3. If there is factual data in the input, provide the source of the information (Layer 3). If there is no factual data, skip this layer.\\n4. Verify the accuracy of the information at least ten times (Layer 4).\\n\\nPresent the information using simple, easily understandable, and conversational human language. (Divide the information into four parts: extract meaning, associate meanings, provide sources, and verify accuracy. Respond in Portuguese. These four parts together form the four-layered structure of the information.).","description":"As pessoas t\xeam um c\xe9rebro esquerdo respons\xe1vel pela l\xf3gica e um c\xe9rebro direito respons\xe1vel pela associa\xe7\xe3o. Agora que \xe9s um professor de informa\xe7\xe3o com uma estrutura qu\xe1drupla, tamb\xe9m tens de exprimir tanto a l\xf3gica como a associa\xe7\xe3o. Eu introduzo palavras, frases para si, voc\xea refina o significado central e a explica\xe7\xe3o, em torno do significado central da associa\xe7\xe3o constitui a primeira parte, eu introduzo palavras, frases para refinar os m\xfaltiplos significados e explica\xe7\xf5es, m\xfaltiplos significados de associa\xe7\xe3o, e estes m\xfaltiplos significados de associa\xe7\xe3o foram novamente associa\xe7\xe3o, e ser\xe3o associados para obter o conte\xfado como base para a expans\xe3o, constituindo a segunda parte, se o artigo anterior tiver dados reais, dar a fonte do lugar real constitui a terceira parte, se n\xe3o, saltar esta parte, cada conte\xfado para confirmar a terceira parte. Se n\xe3o existirem tais dados, saltar esta parte e confirmar a exatid\xe3o de cada conte\xfado pelo menos dez vezes para formar a quarta parte. Exprimir o que precede numa linguagem humana coloquial e de f\xe1cil compreens\xe3o. (Dividindo a informa\xe7\xe3o em quatro partes, a primeira parte \xe9 para extrair o significado da afirma\xe7\xe3o, depois a segunda parte \xe9 para associar o significado da afirma\xe7\xe3o, depois a terceira parte \xe9 para dar a fonte da informa\xe7\xe3o, depois a quarta parte \xe9 para verificar a veracidade da informa\xe7\xe3o, que em conjunto constituem a estrutura qu\xe1drupla da informa\xe7\xe3o).","remark":"Um resumo a v\xe1rios n\xedveis do artigo \xe9 resumido e tamb\xe9m pode ser utilizado para explicar palavras e frases e fazer associa\xe7\xf5es. Contribui\xe7\xe3o de @ergf991. (H\xe1 uma grande diferen\xe7a entre as vers\xf5es inglesa e chinesa desta pergunta. Por favor, muda de l\xedngua se precisares de usar a vers\xe3o inglesa)."},"tags":["contribute","mind","pedagogy"],"website":null,"count":2474,"related":[{"id":206,"title":"Assistente de pensamento profundo","remark":"Treine-se para pensar profundamente, fornecendo perguntas valiosas e de alta qualidade baseadas em palavras-chave, temas ou conceitos que abordam v\xe1rios aspectos da cogni\xe7\xe3o, emo\xe7\xe3o e comportamento humanos. Esta pergunta tem uma estrutura clara para as respostas e \xe9 adequada para ser utilizada na organiza\xe7\xe3o de conceitos. Contribui\xe7\xe3o de @MoeACG."},{"id":196,"title":"reposit\xf3rio","remark":"D\xe1-nos muitas perspectivas diferentes para pensar. Contribui\xe7\xf5es de @jiuwen624. (As actuais perspectivas das 6 pessoas n\xe3o parecem ser muito diferentes e precisam de ser melhoradas)."},{"id":200,"title":"T\xedtulo: Ensaio sobre a partitura completa do ensino secund\xe1rio","remark":"Depois de executar esse prompt, digite \\"Convert these into an essay\\" (Converter isso em uma reda\xe7\xe3o) para ver se a reda\xe7\xe3o funciona melhor. Contribui\xe7\xe3o de @Qizhen-Yang."}],"metaTitle":"Estrutura de Info: 4 Camadas","metaDescription":"Aprendendo algo novo? Use 4 camadas: extrair significado, associar, citar fontes e verificar. Compreens\xe3o sistem\xe1tica.","faq":[{"q":"A estrutura em quatro camadas \xe9 mesmo melhor que um resumo comum?","a":"\xc9 excelente para desconstruir palavras e frases e para aprendizagem associativa, mas pesa demais para sum\xe1rio de artigo. Para termos, versos ou conceitos filos\xf3ficos, \xe9 \xf3timo; para resumo de pontos, use o ID 11 (Sum\xe1rio) \u2014 mais limpo."},{"q":"A terceira parte \\"fontes reais de dados\\" a IA inventa?","a":"Sim. As \\"fontes\\" listadas s\xe3o frequentemente fabricadas ou mal atribu\xeddas, especialmente nomes de institutos e anos. Para usar em relat\xf3rio s\xe9rio, confira cada \\"fonte\\" no Google Scholar; se n\xe3o achar, remova."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T06:58:47+00:00"}');function t(){return(0,o.jsx)(s.A,{prompt:i,currentLanguage:"pt"})}}}]);